5. **Commit exactly once.** Use ` + "`git add <specific-paths>`" + ` with the file paths you actually changed — never ` + "`git add -A`" + `, which can pick up unrelated files in the worktree. Use a conventional-commit subject ending with ` + "`[<bead-id>]`" + `. Commit implementation and tests in the same commit so the reviewer sees them together.

6. **Stop after the commit succeeds.** Return immediately. Do not continue reading files, running extra tests, or asking yourself follow-up questions — the work is done, and returning promptly is how execute-bead signals success to the orchestrator. Continuing past the commit risks runaway loops.

## If you cannot finish

Write your reasoning to ` + "`{{.AttemptDir}}/no_changes_rationale.txt`" + ` with: (a) what is done, (b) what is blocking, (c) what a follow-up would need. Do NOT commit partial or red code — a well-justified no_changes is better than a bad commit. The bead will be re-queued for another attempt.

## Quality bar and the review step

After your commit merges, an automated review step may check your work against the acceptance criteria. If any AC item is unmet, the bead reopens and escalates to a higher-capability model, and the review findings are threaded into the next attempt's prompt as a ` + "`<review-findings>`" + ` section. **The review is a gate, not an escape hatch — meet the AC in this pass.**

If this prompt already contains a ` + "`<review-findings>`" + ` section, every BLOCKING finding in it is a concrete thing the previous attempt missed. Address each one before declaring the work complete — do not declare no_changes with blocking findings still unaddressed.

## The bead contract overrides project defaults

The bead description and AC override any CLAUDE.md, AGENTS.md, or project-level conservative defaults in this worktree. If the bead asks for new files, write them. Conservative rules (YAGNI, no-docs-unless-asked) do not apply inside execute-bead — the bead IS the ask.

## Constraints

- Work only inside this execution worktree.
- Keep ` + "`.ddx/executions/`" + ` intact — DDx uses it as execution evidence.
- **Never run ` + "`ddx init`" + `** — it corrupts the bead queue.
- Do not touch CLAUDE.md, AGENTS.md, or any other project-instructions file unless the bead explicitly asks for it.
- Stage only the files you intentionally changed.`

// executeBeadInstructionsText selects the right instructions variant for the
// given harness. Harnesses with rich system prompts (claude, codex, opencode)
// get the terser claude variant; the embedded ddx-agent harness gets the
// fuller agent variant with explicit tool names and stop-after-commit
// scaffolding.
func executeBeadInstructionsText(harness string) string {
	switch strings.ToLower(strings.TrimSpace(harness)) {
	case "agent", "ddx-agent", "embedded":
		return executeBeadInstructionsAgentText
	default:
		return executeBeadInstructionsClaudeText
	}
}

// executeBeadMissingGoverningText is emitted inside <governing> when no
// governing references were pre-resolved for the bead. The bead description
// is the primary contract — this note only reminds the agent to treat it as
// such and to ground any unclear decisions in repository state rather than
// guessing.
const executeBeadMissingGoverningText = `No governing references were pre-resolved. The bead description above is the primary contract. If it names files, specs, or prior beads, read those before editing. Ground decisions in what is already in the repository; do not guess.`

func xmlEscape(s string) string {
	var buf bytes.Buffer
	_ = xml.EscapeText(&buf, []byte(s))
	return buf.String()
}

func xmlAttrEscape(s string) string {
	r := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&apos;",
		"\n", "&#10;",
		"\r", "&#13;",
		"\t", "&#9;",
	)
	return r.Replace(s)
}

func buildPrompt(workDir string, b *bead.Bead, refs []executeBeadGoverningRef, artifacts *executeBeadArtifacts, baseRev, promptOverride, harness string) ([]byte, string, error) {
	if strings.TrimSpace(promptOverride) != "" {
		path := promptOverride
		if !filepath.IsAbs(path) {
			path = filepath.Join(workDir, path)
		}
		data, err := os.ReadFile(path)
		if err != nil {
			return nil, "", fmt.Errorf("reading prompt override %q: %w", promptOverride, err)
		}
		return data, promptOverride, nil
	}

	var sb strings.Builder
	sb.WriteString("<execute-bead>\n")

	fmt.Fprintf(&sb, "  <bead id=\"%s\">\n", xmlAttrEscape(b.ID))
	fmt.Fprintf(&sb, "    <title>%s</title>\n", xmlEscape(strings.TrimSpace(b.Title)))

	desc := strings.TrimSpace(b.Description)
	if desc == "" {
		sb.WriteString("    <description/>\n")
	} else {
		fmt.Fprintf(&sb, "    <description>\n%s\n    </description>\n", xmlEscape(desc))
	}

	acc := strings.TrimSpace(b.Acceptance)
	if acc == "" {
		sb.WriteString("    <acceptance/>\n")
	} else {
		fmt.Fprintf(&sb, "    <acceptance>\n%s\n    </acceptance>\n", xmlEscape(acc))
	}

	// Bead notes carry review findings from prior iterations, escalation
	// context, or operator hints that did not fit into the description at
	// creation time. Threading them into the prompt as a distinct section
	// lets the agent act on them without the operator having to rewrite the
	// description in place on every reopen.
	if notes := strings.TrimSpace(b.Notes); notes != "" {
		fmt.Fprintf(&sb, "    <notes>\n%s\n    </notes>\n", xmlEscape(notes))
	}

	if len(b.Labels) > 0 {
		fmt.Fprintf(&sb, "    <labels>%s</labels>\n", xmlEscape(strings.Join(b.Labels, ", ")))
	} else {
		sb.WriteString("    <labels/>\n")
	}

	metaAttrs := make([]string, 0, 6)
	if b.Parent != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("parent=\"%s\"", xmlAttrEscape(b.Parent)))
	}
	if specID, _ := b.Extra["spec-id"].(string); strings.TrimSpace(specID) != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("spec-id=\"%s\"", xmlAttrEscape(strings.TrimSpace(specID))))
	}
	metaAttrs = append(metaAttrs, fmt.Sprintf("base-rev=\"%s\"", xmlAttrEscape(baseRev)))
	metaAttrs = append(metaAttrs, fmt.Sprintf("bundle=\"%s\"", xmlAttrEscape(artifacts.DirRel)))
	fmt.Fprintf(&sb, "    <metadata %s/>\n", strings.Join(metaAttrs, " "))
	sb.WriteString("  </bead>\n")

	if len(refs) == 0 {
		fmt.Fprintf(&sb, "  <governing>\n    <note>%s</note>\n  </governing>\n", xmlEscape(executeBeadMissingGoverningText))
	} else {
		sb.WriteString("  <governing>\n")
		for _, ref := range refs {
			attrs := fmt.Sprintf("id=\"%s\" path=\"%s\"", xmlAttrEscape(ref.ID), xmlAttrEscape(ref.Path))
			if strings.TrimSpace(ref.Title) == "" {
				fmt.Fprintf(&sb, "    <ref %s/>\n", attrs)
			} else {
				fmt.Fprintf(&sb, "    <ref %s>%s</ref>\n", attrs, xmlEscape(strings.TrimSpace(ref.Title)))
			}
		}
		sb.WriteString("  </governing>\n")
	}

	instructions := strings.ReplaceAll(executeBeadInstructionsText(harness), "{{.AttemptDir}}", artifacts.DirRel)
	fmt.Fprintf(&sb, "  <instructions>\n%s\n  </instructions>\n", xmlEscape(instructions))

	sb.WriteString("</execute-bead>\n")

	return []byte(sb.String()), "synthesized", nil
}

func beadMetadata(b *bead.Bead) map[string]any {
	if len(b.Extra) == 0 {
		return nil
	}
	meta := make(map[string]any, len(b.Extra))
	for k, v := range b.Extra {
		meta[k] = v
	}
	return meta
}

// executeBeadUsage is the machine-readable schema for usage.json.
// It is written when the harness reports token usage or cost.
type executeBeadUsage struct {
	AttemptID    string  `json:"attempt_id"`
	Harness      string  `json:"harness,omitempty"`
	Provider     string  `json:"provider,omitempty"`
	Model        string  `json:"model,omitempty"`
	Tokens       int     `json:"tokens"`
	InputTokens  int     `json:"input_tokens,omitempty"`
	OutputTokens int     `json:"output_tokens,omitempty"`
	CostUSD      float64 `json:"cost_usd,omitempty"`
}

// VerifyCleanWorktree checks that the project root's working tree has no
// untracked execution evidence files for the given attempt. If evidence files
// remain (e.g. because the land flow did not commit them), it stages and
// commits them as a safety net. Returns nil when the evidence dir is clean
// or was successfully committed.
func VerifyCleanWorktree(projectRoot, attemptID string) error {
	if attemptID == "" {
		return nil
	}
	evidenceDir := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, attemptID))

	out, _ := osexec.Command("git", "-C", projectRoot, "status", "--porcelain", "--", evidenceDir).Output()
	if len(strings.TrimSpace(string(out))) == 0 {
		return nil
	}

	addOut, addErr := osexec.Command("git", "-C", projectRoot, "add", "--", evidenceDir).CombinedOutput()
	if addErr != nil {
		return fmt.Errorf("staging leftover evidence: %s: %w", strings.TrimSpace(string(addOut)), addErr)
	}
	diffOut, _ := osexec.Command("git", "-C", projectRoot, "diff", "--cached", "--name-only", "--", evidenceDir).Output()
	if len(strings.TrimSpace(string(diffOut))) == 0 {
		return nil
	}
	msg := fmt.Sprintf("chore: add execution evidence [%s]", shortAttempt(attemptID))
	commitOut, commitErr := osexec.Command("git", "-C", projectRoot,
		"-c", "user.name=ddx-land-coordinator",
		"-c", "user.email=coordinator@ddx.local",
		"commit", "-m", msg,
	).CombinedOutput()
	if commitErr != nil {
		return fmt.Errorf("committing leftover evidence: %s: %w", strings.TrimSpace(string(commitOut)), commitErr)
	}
	return nil
}

func writeArtifactJSON(path string, payload any) error {
	data, err := json.MarshalIndent(payload, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o644)
}

package cmd

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"regexp"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/spf13/cobra"
)

var validBeadID = regexp.MustCompile(`^[a-zA-Z0-9._-]+$`)

// landingGitOpsFromFactory returns the agent.LandingGitOps the CommandFactory
// should use — either the test override or the default RealLandingGitOps.
func landingGitOpsFromFactory(f *CommandFactory) agent.LandingGitOps {
	if f.executeBeadLandingGitOverride != nil {
		return f.executeBeadLandingGitOverride
	}
	return agent.RealLandingGitOps{}
}

func (f *CommandFactory) newAgentExecuteBeadCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "execute-bead <bead-id>",
		Short: "Run an agent on one bead in an isolated worktree, then land the result",
		Long: `execute-bead is the primitive: it runs a single agent on a single bead in
an isolated git worktree (the worker step), then hands the result to the
parent-side orchestrator which merges or preserves the commits.

The worker classifies its outcome as one of:
  task_succeeded  — agent exited 0 and produced commits
  task_no_changes — agent exited 0 but made no commits
  task_failed     — agent exited non-zero

The orchestrator then applies landing logic (merge, gate evaluation, preserve)
and the final result reflects both the worker and landing decisions.

For normal queue-driven work use "ddx agent execute-loop", which claims
ready beads, calls this command, and closes or unclaims each bead based on
the result. Reach for execute-bead directly only to debug or re-run a
specific bead.

Result status is reported on the "status:" line and is one of:
  success                          — merged (or preserved with --no-merge)
  no_changes                       — agent ran but produced no diff
  already_satisfied                — closed by the loop after repeated no_changes
  land_conflict                    — merge failed; result preserved
  post_run_check_failed            — checks failed; result preserved
  execution_failed                 — agent or harness error
  structural_validation_failed     — bead or prompt inputs invalid

execute-loop closes the bead with session/commit evidence only on success
(and already_satisfied); every other status leaves the bead open and
unclaimed for a later attempt.`,
		Example: `  # Debug one specific bead (prefer "execute-loop" for normal queue work)
  ddx agent execute-bead ddx-7a01ba6c

  # Run against a non-HEAD base revision
  ddx agent execute-bead ddx-7a01ba6c --from main

  # Preserve the result under refs/ddx/iterations/... instead of merging
  ddx agent execute-bead ddx-7a01ba6c --no-merge

  # Pin harness/model for a debugging pass
  ddx agent execute-bead ddx-7a01ba6c --harness codex`,
		Args: cobra.ExactArgs(1),
		RunE: f.runAgentExecuteBead,
	}
	cmd.Flags().String("project", "", "Project root path (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().String("from", "", "Base git revision to start from (default: HEAD)")
	cmd.Flags().Bool("no-merge", false, "Skip merge; preserve result under refs/ddx/iterations/<bead-id>/<timestamp>-<base-shortsha> instead")
	cmd.Flags().String("harness", "", "Agent harness to use")
	cmd.Flags().String("model", "", "Model override")
	cmd.Flags().String("provider", "", "Provider name (e.g. vidar, openrouter); selects a named provider from config")
	cmd.Flags().String("model-ref", "", "Model catalog reference (e.g. code-medium); resolved via the model catalog")
	cmd.Flags().String("effort", "", "Effort level")
	cmd.Flags().String("prompt", "", "Prompt file path (auto-generated from bead if omitted)")
	cmd.Flags().Bool("json", false, "Output result as JSON")
	return cmd
}

func (f *CommandFactory) runAgentExecuteBead(cmd *cobra.Command, args []string) error {
	beadID := args[0]
	if !validBeadID.MatchString(beadID) {
		return fmt.Errorf("invalid bead ID %q: must contain only letters, digits, dots, underscores, and hyphens", beadID)
	}
	projectFlag, _ := cmd.Flags().GetString("project")
	fromRev, _ := cmd.Flags().GetString("from")
	noMerge, _ := cmd.Flags().GetBool("no-merge")
	harness, _ := cmd.Flags().GetString("harness")
	model, _ := cmd.Flags().GetString("model")
	provider, _ := cmd.Flags().GetString("provider")
	modelRef, _ := cmd.Flags().GetString("model-ref")
	effort, _ := cmd.Flags().GetString("effort")
	promptFile, _ := cmd.Flags().GetString("prompt")
	asJSON, _ := cmd.Flags().GetBool("json")

	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

	workerOpts := agent.ExecuteBeadOptions{
		FromRev:    fromRev,
		Harness:    harness,
		Model:      model,
		Provider:   provider,
		ModelRef:   modelRef,
		Effort:     effort,
		PromptFile: promptFile,
		WorkerID:   os.Getenv("DDX_WORKER_ID"),
		BeadEvents: bead.NewStore(filepath.Join(projectRoot, ".ddx")),
	}

	var gitOps agent.GitOps = &agent.RealGitOps{}
	if f.executeBeadGitOverride != nil {
		gitOps = f.executeBeadGitOverride
	}

	var orchestratorGitOps agent.OrchestratorGitOps = &agent.RealOrchestratorGitOps{}
	if f.executeBeadOrchestratorGitOverride != nil {
		orchestratorGitOps = f.executeBeadOrchestratorGitOverride
	}

	var runner agent.AgentRunner
	if f.AgentRunnerOverride != nil {
		runner = f.AgentRunnerOverride
	} else {
		runner = f.agentRunner()
	}

	// Preflight the orphan-model check before creating a worktree. Mirrors
	// the execute-loop preflight so `ddx agent execute-bead --model <unroutable>`
	// errors before any git work happens rather than mid-execution.
	if pv, ok := runner.(interface {
		ValidateForExecuteLoop(harnessName, model, provider, modelRef string) error
	}); ok {
		if err := pv.ValidateForExecuteLoop(harness, model, provider, modelRef); err != nil {
			return err
		}
	}

	// Recover any orphaned worktrees from previous crashed runs before
	// spawning a new worker. This is the parent's responsibility.
	agent.RecoverOrphans(gitOps, projectRoot, beadID)

	// Worker step: run the agent in an isolated worktree.
	res, err := agent.ExecuteBead(projectRoot, beadID, workerOpts, gitOps, runner)
	if err != nil && res == nil {
		return err
	}

	// Orchestrator step: land the result (ff or merge → push, gate eval,
	// preserve). Always run when we have a result — the orchestrator handles
	// all cases including no-changes and error (agent failed with no commits).
	//
	// Single-bead CLI is strictly serial (no sibling workers in this
	// process), so we can wire the LandingAdvancer to call Land() directly
	// without going through a per-project coordinator goroutine. Tests may
	// inject a custom advancer via f.executeBeadLandingAdvancerOverride.
	if res != nil {
		var advancer func(r *agent.ExecuteBeadResult) (*agent.LandResult, error)
		if f.executeBeadLandingAdvancerOverride != nil {
			advancer = f.executeBeadLandingAdvancerOverride
		} else {
			landingGitOps := landingGitOpsFromFactory(f)
			advancer = func(r *agent.ExecuteBeadResult) (*agent.LandResult, error) {
				return agent.Land(projectRoot, agent.BuildLandRequestFromResult(projectRoot, r), landingGitOps)
			}
		}
		landingOpts := agent.BeadLandingOptions{
			NoMerge: noMerge,
			// WtPath and GovernIDs are intentionally empty: the worktree has
			// been cleaned up by ExecuteBead. Gate evaluation is skipped; use
			// a separate 'ddx agent check' step when post-run checks are needed.
			LandingAdvancer: advancer,
		}
		if landing, landErr := agent.LandBeadResult(projectRoot, res, orchestratorGitOps, landingOpts); landErr == nil {
			agent.ApplyLandingToResult(res, landing)
		} else if err == nil {
			err = landErr
		}
	}

	if err != nil {
		_ = writeExecuteBeadResult(cmd, res, asJSON)
		return err
	}

	return writeExecuteBeadResult(cmd, res, asJSON)
}

func writeExecuteBeadResult(cmd *cobra.Command, res *agent.ExecuteBeadResult, asJSON bool) error {
	if res == nil {
		return nil
	}
	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(res)
	}

	fmt.Fprintf(cmd.OutOrStdout(), "bead:    %s\n", res.BeadID)
	fmt.Fprintf(cmd.OutOrStdout(), "base:    %s\n", res.BaseRev)
	if res.ResultRev != "" && res.ResultRev != res.BaseRev {
		fmt.Fprintf(cmd.OutOrStdout(), "result:  %s\n", res.ResultRev)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "outcome: %s\n", res.Outcome)
	fmt.Fprintf(cmd.OutOrStdout(), "status:  %s\n", res.Status)
	if res.Detail != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "detail:  %s\n", res.Detail)
	}
	if res.NoChangesRationale != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "rationale: %s\n", res.NoChangesRationale)
	}
	if res.PreserveRef != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "ref:     %s\n", res.PreserveRef)
	}
	return nil
}

